SELECT sub.基本工事コード, sub.基本工事名, sub.工事コード, sub.工事名, sub.枝番工事コード, sub.追加工事名称, sub.施工管轄組織名, sub.担当者名, sub.着工日, sub.完成日, sub.工事価格, sub.受注時粗利額, Format(sub.受注時粗利率, "Percent") AS 受注時粗利率, Format(sub.原価S粗利率, "Percent") AS 原価S粗利率, Format(sub.粗利率差, "0.00%") AS 粗利率差, sub.今後支払予定, sub.err粗利率差, sub.err当月支払, sub.err完工日超過支払, sub.除外備考
FROM (SELECT g.基本工事コード, g.基本工事名, g.工事コード, g.工事名, g.枝番工事コード, g.追加工事名称, kt.施工管轄組織名, g.担当者名, g.着工 AS 着工日, g.完成 AS 完成日, g.工事価格, kt.粗利益額 AS 受注時粗利額, IIf(Nz(kt.工事価格,0)=0,Null,kt.粗利益額/kt.工事価格) AS 受注時粗利率, g.粗利率 AS 原価S粗利率, (IIf(Nz(kt.工事価格,0)=0,Null,kt.粗利益額/kt.工事価格)-g.粗利率) AS 粗利率差, g.今後支払予定, IIf(Nz(ex.除外_利益エラー,False)=False AND Abs(Nz(IIf(Nz(kt.工事価格,0)=0,Null,kt.粗利益額/kt.工事価格)-g.粗利率,0))>0.2,"粗利率エラー",Null) AS err粗利率差, IIf(Nz(ex.除外_支払エラー,False)=False And Nz(g.既払高：総額,0)<>Nz(g.当月より前の支払金額,0)+Nz(g.当月支払金額,0),"当月支払金額エラー",Null) AS err当月支払, IIf(Nz(ex.除外_支払エラー,False)=False AND Not IsNull(g.完成) AND Nz(g.今後支払予定,0)-Nz(g.当月以降予定金額,0)<>0 AND DateDiff("m",g.完成,Date())>=2 AND g.完成<DateSerial(Year(Date()),Month(Date()),1),"支払予定" & DateDiff("m",g.完成,Date()) & "月超過エラー",Null) AS err完工日超過支払, ex.備考 AS 除外備考, kt.施工管轄組織コード FROM (at_Genka_Edaban AS g LEFT JOIN q_Icube_WithMngNo AS kt ON (g.工事コード = kt.工事コード) AND (g.管理番号 = kt.管理番号)) LEFT JOIN at_Genka_Edaban_Exclusion AS ex ON g.枝番工事コード = ex.枝番工事コード)  AS sub
WHERE (sub.今後支払予定 < 0)     OR (sub.err粗利率差 IS NOT NULL)     OR (sub.err当月支払 IS NOT NULL)     OR (sub.err完工日超過支払 IS NOT NULL)
ORDER BY sub.施工管轄組織コード, sub.工事コード;
